// // This register is loaded with data on the falling edge of the clock and cleared on the rising edge of the reset.
module register_with_async_reset (
    input clk,
    input reset,
    input [3:0] data_in,
    output reg [3:0] data_out
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            data_out <= 4'b0000;
        else
            data_out <= data_in;
    end

endmodule
